+                entry.map_or(0, |metadata| metadata.dependency_count),
+                *dependency_counts.get(id).unwrap_or(&0)
+            );
+            assert_eq!(
+                entry.map_or(0, |metadata| metadata.dependent_count),
+                *dependent_counts.get(id).unwrap_or(&0)
+            );
+        }
+    }
